// Auth System
let users = [];
let currentUser = null;
try {
  users = JSON.parse(localStorage.getItem('velora_users')) || [];
  currentUser = JSON.parse(localStorage.getItem('velora_current_user')) || null;
} catch (e) {
  console.warn('localStorage is not available:', e);
}

function register(name, email, phone, password) {
  if (users.find(u => u.email === email)) {
    return { success: false, error: "Email already registered" };
  }
  
  const newUser = { id: Date.now(), name, email, phone, password };
  users.push(newUser);
  try {
    localStorage.setItem('velora_users', JSON.stringify(users));
  } catch (e) {
    console.warn('localStorage is not available:', e);
  }
  
  // Auto login
  currentUser = newUser;
  try {
    localStorage.setItem('velora_current_user', JSON.stringify(currentUser));
  } catch (e) {
    console.warn('localStorage is not available:', e);
  }
  updateAuthUI();
  
  return { success: true };
}

function login(email, password) {
  const user = users.find(u => u.email === email && u.password === password);
  if (user) {
    currentUser = user;
    try {
      localStorage.setItem('velora_current_user', JSON.stringify(currentUser));
    } catch (e) {
      console.warn('localStorage is not available:', e);
    }
    updateAuthUI();
    return { success: true };
  }
  return { success: false, error: "Invalid email or password" };
}

function logout() {
  currentUser = null;
  try {
    localStorage.removeItem('velora_current_user');
  } catch (e) {
    console.warn('localStorage is not available:', e);
  }
  updateAuthUI();
  window.location.href = 'login.html';
}

function isLoggedIn() {
  return currentUser !== null;
}

function updateAuthUI() {
  const authLinks = document.querySelectorAll('.auth-link');
  authLinks.forEach(link => {
    if (isLoggedIn()) {
      link.href = 'account.html';
      link.innerHTML = `<span>${currentUser.name.split(' ')[0]}</span>`;
    } else {
      link.href = 'login.html';
      link.innerHTML = `<span>Login</span>`;
    }
  });
}

document.addEventListener('DOMContentLoaded', () => {
  updateAuthUI();
});

